#!/usr/bin/env bash
set -euo pipefail;source "$(dirname "$0")/lib/android-test.sh";serial=emulator-5554;from=0.9.0;from_code=9000;to=1.0.1;rebuild=false;prepare=false;while (($#));do case "$1" in --serial)serial="${2:?}";shift 2;;--from-version)from="${2:?}";shift 2;;--from-version-code)from_code="${2:?}";shift 2;;--to-version)to="${2:?}";shift 2;;--rebuild-baseline|--published-v100-migration)rebuild=true;shift;;--prepare-baseline-only)prepare=true;shift;;*)archphene_die "unknown argument: $1";;esac;done;if [[ "$rebuild" == true ]];then "$ARCHPHENE_SCRIPTS_DIR/build-install-linux-manager-stub.sh" --skip-install --version-code "$from_code" --version-name "$from";fi;[[ "$prepare" == false ]] || { archphene_note "Baseline $from prepared.";exit;};archphene_test_init "$serial";package=org.archpheneos.manager;archphene_adb_run shell am start -W -n "$package/.MainActivity" >/dev/null;archphene_wait_ui_text "Archphene update $to available" github-update 90;ui="$ARCHPHENE_UI";archphene_tap_ui_pattern "$ui" 'content-desc="Archphene update[^\"]*available' update;archphene_wait_ui_text 'Install selected version' github-selected 30;archphene_tap_text "$ARCHPHENE_UI" 'Install selected version';archphene_wait_ui_text Update github-confirm 45;archphene_tap_text "$ARCHPHENE_UI" Update;archphene_note "Live GitHub self-update passed: $from -> $to with Android confirmation."
